class Solution {
    public String minimizeStringValue(String s) {
        StringBuilder sb = new StringBuilder();
        int[] count = new int[26];
        int index = 0;
        for (char c : s.toCharArray()) {
            if (c == '?') {
                char newChar = 'a';
                while (count[newChar - 'a'] > 0) {
                    newChar++;
                }
                count[newChar - 'a']++;
                sb.append(newChar);
            } else {
                count[c - 'a']++;
                sb.append(c);
            }
        }
        return sb.toString();
    }
}
